    const invoiceCards=invoices.map(x=>{const items=state.supplierInvoiceItems19.filter(i=>i.invoice_id===x.id),locked=['approved','posted','paid'].includes(x.status);return `<article class="pc-record-card"><header><div><small>${esc(x.invoice_number||'INVOICE')}</small><h3>${esc(supplierName(x.supplier_id))}</h3><p>${date(x.invoice_date)} · due ${date(x.due_date)} · ${esc(x.currency||'AED')}</p></div>${status19(x.status)}</header><div class="pc-record-metrics"><span>Subtotal <b>${fmt19(x.subtotal)} AED</b></span><span>VAT <b>${fmt19(x.vat_amount)} AED</b></span><span>Total <b>${fmt19(x.total_amount)} AED</b></span><span>Paid <b>${fmt19(x.paid_amount)} AED</b></span><span>Match <b>${esc(x.match_status||'not checked')}</b></span></div><div class="pc-record-actions"><button class="btn" onclick="openSupplierInvoice19('${project.id}','${x.id}')">Edit / payment</button><button class="btn primary" onclick="openSupplierInvoiceItem19('${project.id}','${x.id}')" ${locked?'disabled':''}>＋ Invoice line</button>${x.document_url?`<a class="btn" href="${href19(x.document_url)}" target="_blank" rel="noopener noreferrer">Document</a>`:''}</div>${items.length?table19(['PO LINE','WBS','DESCRIPTION','QTY','UNIT','RATE','NET / TOTAL'],items.map(i=>{const po=state.procurementCommitmentItems19.find(v=>v.id===i.commitment_item_id),c=costCode19(i.cost_code_id);return [esc(po?.description||'Unlinked'),esc(c.code),esc(i.description),n19(i.quantity),esc(i.unit||'pcs'),fmt19(i.unit_price),`${fmt19(i.net_amount)} / ${fmt19(i.total_amount)}`]}),'pc-inner-table'):''}</article>`}).join('')||empty19('Supplier invoices пока нет','Зафиксируйте счёт поставщика и свяжите каждую строку с Purchase Order для 3-way match.',`<button class="btn primary" onclick="openSupplierInvoice19('${project.id}')">＋ Supplier invoice</button>`);
